// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::mod11::{self, CheckDigit, Rule, SeloError};

const DV: CheckDigit = CheckDigit { weights: &[3, 2, 9, 8, 7, 6, 5, 4, 3, 2], rule: Rule::ModRemainder, remainder_to0: &[0, 1], multiply_by10: false, encode_x_at: 0, encode_zero_at: 0 };

/// Report whether value is a valid Pis.
pub fn validate_pis(value: &str) -> bool {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return false;
    }
    if mod11::all_equal(&d) {
        return false;
    }
    let digits: Vec<i32> = d.bytes().map(|c| (c - b'0') as i32).collect();
    let dv = mod11::compute_digit(mod11::weighted_sum(&digits[0..10], DV.weights, false), &DV);
    dv == digits[10]
}

/// Render the canonical mask, or return an error on bad length.
pub fn format_pis(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return Err(SeloError::InvalidLength);
    }
    Ok(format!("{}.{}.{}-{}", &d[0..3], &d[3..8], &d[8..10], &d[10..11]))
}

/// Return a random, valid Pis (unformatted).
pub fn generate_pis() -> String {
    loop {
        let mut b: Vec<i32> = Vec::with_capacity(11);
        for _ in 0..10 {
            b.push(mod11::rand_int(9) as i32);
        }
        b.push(mod11::compute_digit(mod11::weighted_sum(&b, DV.weights, false), &DV));
        let out: String = b.iter().map(|n| n.to_string()).collect();
        if !mod11::all_equal(&out) {
            return out;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/pis.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_pis(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_pis(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_pis(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_pis();
            assert!(validate_pis(&v), "generate produced invalid: {}", v);
        }
    }
}
